def prime_fib(n: int):
    def is_prime(num):
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    def fibonacci():
        a, b = 0, 1
        while True:
            yield b
            a, b = b, a + b

    count = 0
    for fib in fibonacci():
        if is_prime(fib):
            count += 1
            if count == n:
                return fib

